+fn valid_input() -> EnvelopeInput {
+    let upper = test_upper_bound();
+    let required: BTreeSet<FlowRule> = upper
+        .iter()
+        .filter(|r| r.source_label.can_flow_to(&r.sink_clearance))
+        .cloned()
+        .collect();
+    let denied: BTreeSet<FlowRule> = upper
+        .iter()
